/**
 * Corgi Dashboard — SkillCard
 * Compact skill card with a popover for full details.
 */
import React, { useRef, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ExternalLink, AlertTriangle, CheckCircle, XCircle } from 'lucide-react';
import type { SkillStatusEntry } from '../../gateway/types';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type SkillStatus = 'ok' | 'error' | 'disabled';

export interface SkillCardProps {
  skill: SkillStatusEntry;
  compact?: boolean;
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

const STATUS_COLOR: Record<SkillStatus, string> = {
  ok: 'var(--success)',
  error: 'var(--warning)',
  disabled: 'var(--error)',
};

const STATUS_ICON: Record<SkillStatus, React.ReactNode> = {
  ok: <CheckCircle size={11} />,
  error: <AlertTriangle size={11} />,
  disabled: <XCircle size={11} />,
};

const STATUS_LABEL: Record<SkillStatus, string> = {
  ok: 'Ready',
  error: 'Missing deps',
  disabled: 'Disabled',
};

function deriveEmoji(name: string): string {
  // A few well-known skill emojis
  const map: Record<string, string> = {
    github: '🐙',
    gog: '📧',
    weather: '🌤',
    'apple-notes': '📝',
    'apple-reminders': '✅',
    'bear-notes': '🐻',
    things: '✅',
    obsidian: '💎',
    gemini: '✨',
    oracle: '🔮',
    wacli: '💬',
    imsg: '💬',
    himalaya: '📬',
    sonos: '🔊',
    blucli: '🔵',
    openhue: '💡',
    eightctl: '🛌',
    camsnap: '📷',
    summarize: '📄',
    'video-frames': '🎬',
    songsee: '🎵',
    peekaboo: '👀',
    xurl: '🐦',
    'nano-pdf': '📑',
    'skill-creator': '🛠',
    clawhub: '🦀',
    healthcheck: '🛡',
    blogwatcher: '📡',
    mcporter: '🔌',
    gifgrep: '🎞',
    ordercli: '🍔',
  };
  return map[name] ?? '📦';
}

/* ------------------------------------------------------------------ */
/*  Popover content                                                    */
/* ------------------------------------------------------------------ */

interface SkillPopoverProps {
  skill: SkillStatusEntry;
  status: SkillStatus;
}

const SkillPopover: React.FC<SkillPopoverProps> = ({ skill, status }) => {
  const color = STATUS_COLOR[status];

  return (
    <motion.div
      initial={{ opacity: 0, y: 6, scale: 0.96 }}
      animate={{ opacity: 1, y: 0, scale: 1 }}
      exit={{ opacity: 0, y: 4, scale: 0.96 }}
      transition={{ duration: 0.15, ease: [0.16, 1, 0.3, 1] }}
      style={{
        position: 'absolute',
        bottom: 'calc(100% + 6px)',
        left: '50%',
        transform: 'translateX(-50%)',
        width: 260,
        background: 'var(--bg-tertiary)',
        border: '1px solid var(--border-default)',
        borderRadius: 'var(--radius-lg)',
        padding: 'var(--space-3)',
        boxShadow: 'var(--shadow-large)',
        zIndex: 'var(--z-popover)',
        pointerEvents: 'none',
      }}
    >
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-1_5)', marginBottom: 'var(--space-2)' }}>
        <span style={{ fontSize: 16 }}>{deriveEmoji(skill.name)}</span>
        <span style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)' }}>
          {skill.name}
        </span>
        <span style={{ marginLeft: 'auto', color, display: 'flex', alignItems: 'center', gap: 3, fontSize: 'var(--text-xs)' }}>
          {STATUS_ICON[status]}
          {STATUS_LABEL[status]}
        </span>
      </div>

      {/* Description */}
      {skill.description && (
        <p style={{ fontSize: 'var(--text-xs)', color: 'var(--text-secondary)', lineHeight: 'var(--leading-normal)', margin: 0, marginBottom: 'var(--space-2)' }}>
          {skill.description}
        </p>
      )}

      {/* Error / missing deps */}
      {skill.error && (
        <div
          style={{
            marginTop: 'var(--space-2)',
            padding: 'var(--space-1_5) var(--space-2)',
            background: 'var(--warning-muted)',
            borderRadius: 'var(--radius-sm)',
            fontSize: 'var(--text-xs)',
            color: 'var(--warning)',
            fontFamily: 'var(--font-mono)',
          }}
        >
          {skill.error}
        </div>
      )}

      {/* Location */}
      {skill.location && (
        <div style={{ marginTop: 'var(--space-2)', fontSize: 'var(--text-xs)', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)' }}>
          📁 {skill.location}
        </div>
      )}
    </motion.div>
  );
};

/* ------------------------------------------------------------------ */
/*  SkillCard                                                          */
/* ------------------------------------------------------------------ */

export const SkillCard: React.FC<SkillCardProps> = ({ skill, compact = false }) => {
  const [showPopover, setShowPopover] = useState(false);
  const status: SkillStatus = skill.status ?? 'ok';
  const color = STATUS_COLOR[status];
  const emoji = deriveEmoji(skill.name);

  return (
    <div
      style={{ position: 'relative' }}
      onMouseEnter={() => setShowPopover(true)}
      onMouseLeave={() => setShowPopover(false)}
    >
      <motion.div
        whileHover={{ scale: 1.02 }}
        whileTap={{ scale: 0.97 }}
        transition={{ duration: 0.12 }}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-1_5)',
          padding: compact ? 'var(--space-1) var(--space-1_5)' : 'var(--space-1_5) var(--space-2)',
          background: 'var(--bg-tertiary)',
          border: '1px solid var(--border-subtle)',
          borderRadius: 'var(--radius-md)',
          cursor: 'default',
          userSelect: 'none',
        }}
      >
        <span style={{ fontSize: compact ? 12 : 14 }}>{emoji}</span>
        <span
          style={{
            fontSize: 'var(--text-xs)',
            color: 'var(--text-primary)',
            fontWeight: 'var(--font-medium)',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
            maxWidth: compact ? 80 : 120,
          }}
          title={skill.name}
        >
          {skill.name}
        </span>
        <span style={{ color, display: 'flex', alignItems: 'center', marginLeft: 'auto' }}>
          {STATUS_ICON[status]}
        </span>
      </motion.div>

      {/* Popover */}
      <AnimatePresence>
        {showPopover && <SkillPopover skill={skill} status={status} />}
      </AnimatePresence>
    </div>
  );
};

export default SkillCard;
