/**
 * Corgi Dashboard — DashboardSection
 * Collapsible section wrapper used by CloudflareTiles, SkillsFolder, etc.
 */
import React, { useCallback, useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ChevronDown } from 'lucide-react';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface DashboardSectionProps {
  /** Unique key used to persist collapsed state in localStorage */
  storageKey: string;
  title: React.ReactNode;
  /** Subtitle / badge shown next to the title */
  badge?: React.ReactNode;
  /** Optional action button (rendered on the right of the header) */
  action?: React.ReactNode;
  /** Default collapsed state when no persisted value exists */
  defaultCollapsed?: boolean;
  children: React.ReactNode;
  className?: string;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const DashboardSection: React.FC<DashboardSectionProps> = ({
  storageKey,
  title,
  badge,
  action,
  defaultCollapsed = false,
  children,
  className = '',
}) => {
  // Restore from localStorage
  const [collapsed, setCollapsed] = useState<boolean>(() => {
    try {
      const saved = localStorage.getItem(`dashboard-section:${storageKey}`);
      if (saved !== null) return saved === 'true';
    } catch {}
    return defaultCollapsed;
  });

  // Persist to localStorage whenever it changes
  useEffect(() => {
    try {
      localStorage.setItem(`dashboard-section:${storageKey}`, String(collapsed));
    } catch {}
  }, [collapsed, storageKey]);

  const toggle = useCallback(() => setCollapsed((v) => !v), []);

  return (
    <div
      className={className}
      style={{
        background: 'var(--bg-secondary)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 'var(--radius-lg)',
        overflow: 'hidden',
      }}
    >
      {/* ── Header ─────────────────────────────────────────────────── */}
      <button
        onClick={toggle}
        style={{
          width: '100%',
          display: 'flex',
          alignItems: 'center',
          gap: 'var(--space-2)',
          padding: 'var(--space-2) var(--space-3)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
          color: 'var(--text-secondary)',
          fontSize: 'var(--text-xs)',
          fontWeight: 'var(--font-semibold)',
          letterSpacing: 'var(--tracking-wide)',
          textTransform: 'uppercase',
        }}
      >
        {/* Chevron */}
        <motion.span
          animate={{ rotate: collapsed ? -90 : 0 }}
          transition={{ duration: 0.2, ease: [0.16, 1, 0.3, 1] }}
          style={{ display: 'flex', alignItems: 'center', flexShrink: 0 }}
        >
          <ChevronDown size={12} />
        </motion.span>

        {/* Title */}
        <span style={{ color: 'var(--text-primary)', flexShrink: 0 }}>{title}</span>

        {/* Badge */}
        {badge && (
          <span
            style={{
              fontSize: 'var(--text-xs)',
              color: 'var(--text-muted)',
              fontWeight: 'var(--font-normal)',
              textTransform: 'none',
              letterSpacing: 'normal',
            }}
          >
            {badge}
          </span>
        )}

        {/* Spacer */}
        <span style={{ flex: 1 }} />

        {/* Action button (stop toggle propagation) */}
        {action && (
          <span
            onClick={(e) => e.stopPropagation()}
            style={{ display: 'flex', alignItems: 'center' }}
          >
            {action}
          </span>
        )}
      </button>

      {/* ── Body ───────────────────────────────────────────────────── */}
      <AnimatePresence initial={false}>
        {!collapsed && (
          <motion.div
            key="body"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.25, ease: [0.16, 1, 0.3, 1] }}
            style={{ overflow: 'hidden' }}
          >
            <div
              style={{
                borderTop: '1px solid var(--border-subtle)',
                padding: 'var(--space-3)',
              }}
            >
              {children}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default DashboardSection;
