/**
 * Corgi Dashboard — CloudflareTiles
 * Horizontal scrollable row of Cloudflare project tiles.
 * Fetches from Django backend: GET /api/cloudflare/projects/
 */
import React, { useCallback, useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';
import { Settings, RefreshCw } from 'lucide-react';
import { Skeleton } from '../../theme/skeleton';
import { DashboardSection } from './DashboardSection';
import { CloudflareTileCard, CloudflareAddTile } from './CloudflareTileCard';
import type { CloudflareProject, CloudflareProjectStatus } from './CloudflareTileCard';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

interface ApiProject {
  id?: string;
  name: string;
  subdomain?: string;
  domains?: string[];
  latest_deployment?: {
    id?: string;
    url?: string;
    created_on?: string;
    environment?: string;
    stage?: { name?: string };
  };
  production_branch?: string;
}

interface UseCloudflareProjectsReturn {
  projects: CloudflareProject[];
  loading: boolean;
  error: string | null;
  refresh: () => void;
}

/* ------------------------------------------------------------------ */
/*  Relative time helper                                               */
/* ------------------------------------------------------------------ */

function relativeTime(isoString?: string): string | undefined {
  if (!isoString) return undefined;
  const diff = Date.now() - new Date(isoString).getTime();
  if (diff < 0) return 'just now';
  const secs = Math.floor(diff / 1000);
  if (secs < 60) return 'just now';
  const mins = Math.floor(secs / 60);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  return `${days}d ago`;
}

/* ------------------------------------------------------------------ */
/*  useCloudflareProjects hook                                         */
/* ------------------------------------------------------------------ */

export function useCloudflareProjects(): UseCloudflareProjectsReturn {
  const [projects, setProjects] = useState<CloudflareProject[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchProjects = useCallback(async () => {
    try {
      const res = await fetch('/api/cloudflare/projects/');
      if (res.status === 401 || res.status === 403) {
        setError('Configure Cloudflare API token');
        setProjects([]);
        return;
      }
      if (!res.ok) {
        setError(`API error: ${res.status}`);
        return;
      }
      const data = await res.json();
      const raw: ApiProject[] = Array.isArray(data)
        ? data
        : data.projects ?? data.results ?? [];

      const mapped: CloudflareProject[] = raw.map((p) => {
        // Derive status from latest deployment stage
        const stageName = p.latest_deployment?.stage?.name ?? '';
        let status: CloudflareProjectStatus = 'unknown';
        if (['queued', 'initialize', 'clone_repo', 'build', 'deploy'].includes(stageName)) {
          status = 'building';
        } else if (stageName === 'failure') {
          status = 'failed';
        } else if (stageName === 'success' || p.latest_deployment?.url) {
          status = 'active';
        }

        const productionUrl = p.latest_deployment?.url
          ? `https://${p.latest_deployment.url}`
          : p.subdomain
          ? `https://${p.subdomain}.pages.dev`
          : undefined;

        return {
          id: p.id ?? p.name,
          name: p.name,
          status,
          productionUrl,
          dashboardUrl: `https://dash.cloudflare.com/?to=/:account/pages/view/${p.name}`,
          lastDeploy: p.latest_deployment?.created_on,
          lastDeployRelative: relativeTime(p.latest_deployment?.created_on),
          customDomains: p.domains?.filter((d) => !d.endsWith('.pages.dev')),
        };
      });

      setProjects(mapped);
      setError(null);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      // Network error likely means CF not configured or backend unreachable
      if (msg.includes('Failed to fetch') || msg.includes('NetworkError')) {
        setError('Configure Cloudflare API token');
      } else {
        setError(msg);
      }
    } finally {
      setLoading(false);
    }
  }, []);

  const refresh = useCallback(() => {
    setLoading(true);
    fetchProjects();
  }, [fetchProjects]);

  // Initial fetch
  useEffect(() => {
    fetchProjects();
  }, [fetchProjects]);

  // Auto-refresh every 60 seconds
  useEffect(() => {
    timerRef.current = setInterval(fetchProjects, 60_000);
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [fetchProjects]);

  return { projects, loading, error, refresh };
}

/* ------------------------------------------------------------------ */
/*  CloudflareTiles                                                    */
/* ------------------------------------------------------------------ */

export const CloudflareTiles: React.FC = () => {
  const { projects, loading, error, refresh } = useCloudflareProjects();

  const actionButton = (
    <button
      onClick={refresh}
      title="Refresh"
      style={{
        background: 'none',
        border: 'none',
        cursor: 'pointer',
        color: 'var(--text-muted)',
        display: 'flex',
        alignItems: 'center',
        padding: 'var(--space-1)',
        borderRadius: 'var(--radius-sm)',
        transition: 'color var(--transition-fast)',
      }}
      onMouseEnter={(e) => ((e.currentTarget as HTMLElement).style.color = 'var(--text-primary)')}
      onMouseLeave={(e) => ((e.currentTarget as HTMLElement).style.color = 'var(--text-muted)')}
    >
      <RefreshCw size={12} />
    </button>
  );

  const badge = !loading && !error
    ? `${projects.length} project${projects.length !== 1 ? 's' : ''}`
    : undefined;

  return (
    <DashboardSection
      storageKey="cloudflare-tiles"
      title="☁️ Cloudflare"
      badge={badge}
      action={actionButton}
    >
      {/* ── Loading ─────────────────────────────────────────────────── */}
      {loading && (
        <div style={{ display: 'flex', gap: 'var(--space-2)', overflowX: 'auto', paddingBottom: 4 }}>
          {[1, 2, 3].map((i) => (
            <Skeleton
              key={i}
              variant="card"
              width={200}
              height={110}
              className="flex-shrink-0"
            />
          ))}
        </div>
      )}

      {/* ── Error ───────────────────────────────────────────────────── */}
      {!loading && error && (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 'var(--space-2)',
            padding: 'var(--space-3)',
            background: 'var(--warning-muted)',
            borderRadius: 'var(--radius-md)',
            fontSize: 'var(--text-xs)',
            color: 'var(--warning)',
          }}
        >
          <Settings size={13} />
          <span>{error}</span>
          <a
            href="/settings/integrations"
            style={{ color: 'var(--accent-primary)', textDecoration: 'underline', marginLeft: 4 }}
          >
            Configure
          </a>
        </div>
      )}

      {/* ── Tiles ───────────────────────────────────────────────────── */}
      {!loading && !error && (
        <div
          style={{
            display: 'flex',
            gap: 'var(--space-2)',
            overflowX: 'auto',
            paddingBottom: 4,
            /* Custom scrollbar */
            scrollbarWidth: 'thin',
            scrollbarColor: 'var(--scrollbar-thumb) var(--scrollbar-track)',
          }}
        >
          {projects.map((project) => (
            <CloudflareTileCard key={project.id} project={project} />
          ))}
          <CloudflareAddTile
            onClick={() => window.open('https://dash.cloudflare.com/?to=/:account/pages', '_blank', 'noopener,noreferrer')}
          />
        </div>
      )}

      {/* ── Empty state ─────────────────────────────────────────────── */}
      {!loading && !error && projects.length === 0 && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          style={{
            textAlign: 'center',
            padding: 'var(--space-4)',
            color: 'var(--text-muted)',
            fontSize: 'var(--text-xs)',
          }}
        >
          No Cloudflare Pages projects found.
        </motion.div>
      )}
    </DashboardSection>
  );
};

export default CloudflareTiles;
