/**
 * Corgi Dashboard — SkillsFolder
 * Collapsible section showing all installed skills.
 * Data via gateway: skills.status RPC
 */
import React, { useCallback, useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { RefreshCw, Search } from 'lucide-react';
import { useSkills } from '../../gateway/hooks';
import { Skeleton } from '../../theme/skeleton';
import { DashboardSection } from './DashboardSection';
import { SkillCard } from './SkillCard';
import type { SkillStatusEntry } from '../../gateway/types';

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const SkillsFolder: React.FC = () => {
  const { fetchSkills } = useSkills();
  const [skills, setSkills] = useState<SkillStatusEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [hasLoaded, setHasLoaded] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState('');

  const loadSkills = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetchSkills();
      if (res?.skills) {
        setSkills(res.skills);
      }
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load skills');
    } finally {
      setLoading(false);
      setHasLoaded(true);
    }
  }, [fetchSkills]);

  // Load on first mount
  useEffect(() => {
    loadSkills();
  }, [loadSkills]);

  // Filtered skills
  const filtered = search.trim()
    ? skills.filter(
        (s) =>
          s.name.toLowerCase().includes(search.toLowerCase()) ||
          s.description?.toLowerCase().includes(search.toLowerCase()),
      )
    : skills;

  // Counts
  const readyCount = skills.filter((s) => (s.status ?? 'ok') === 'ok').length;
  const issueCount = skills.filter((s) => s.status === 'error' || s.status === 'disabled').length;

  const badge = hasLoaded
    ? `${skills.length} installed${issueCount > 0 ? ` · ${issueCount} ⚠` : ''}`
    : undefined;

  const actionButton = (
    <button
      onClick={loadSkills}
      title="Refresh skills"
      style={{
        background: 'none',
        border: 'none',
        cursor: 'pointer',
        color: 'var(--text-muted)',
        display: 'flex',
        alignItems: 'center',
        padding: 'var(--space-1)',
        borderRadius: 'var(--radius-sm)',
        transition: 'color var(--transition-fast)',
      }}
      onMouseEnter={(e) => ((e.currentTarget as HTMLElement).style.color = 'var(--text-primary)')}
      onMouseLeave={(e) => ((e.currentTarget as HTMLElement).style.color = 'var(--text-muted)')}
    >
      <motion.div animate={loading ? { rotate: 360 } : { rotate: 0 }} transition={{ duration: 0.6, repeat: loading ? Infinity : 0, ease: 'linear' }}>
        <RefreshCw size={12} />
      </motion.div>
    </button>
  );

  return (
    <DashboardSection
      storageKey="skills-folder"
      title="📂 Skills"
      badge={badge}
      action={actionButton}
      defaultCollapsed
    >
      {/* Search */}
      {hasLoaded && skills.length > 6 && (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 'var(--space-1_5)',
            marginBottom: 'var(--space-2)',
            background: 'var(--bg-input)',
            border: '1px solid var(--border-subtle)',
            borderRadius: 'var(--radius-md)',
            padding: 'var(--space-1) var(--space-2)',
          }}
        >
          <Search size={11} style={{ color: 'var(--text-muted)', flexShrink: 0 }} />
          <input
            type="text"
            placeholder="Filter skills…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{
              background: 'none',
              border: 'none',
              outline: 'none',
              fontSize: 'var(--text-xs)',
              color: 'var(--text-primary)',
              width: '100%',
              caretColor: 'var(--accent-primary)',
            }}
          />
        </div>
      )}

      {/* Loading */}
      {loading && !hasLoaded && (
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--space-1)' }}>
          {Array.from({ length: 8 }).map((_, i) => (
            <Skeleton key={i} variant="rect" width={110} height={32} />
          ))}
        </div>
      )}

      {/* Error */}
      {error && (
        <div
          style={{
            fontSize: 'var(--text-xs)',
            color: 'var(--error)',
            padding: 'var(--space-2)',
            background: 'var(--error-muted)',
            borderRadius: 'var(--radius-md)',
          }}
        >
          {error}
        </div>
      )}

      {/* Skills grid */}
      {!loading && !error && filtered.length > 0 && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: 'var(--space-1)',
          }}
        >
          {filtered.map((skill) => (
            <SkillCard key={skill.name} skill={skill} compact />
          ))}
        </motion.div>
      )}

      {/* Empty search */}
      {!loading && !error && filtered.length === 0 && hasLoaded && (
        <p style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)', textAlign: 'center', padding: 'var(--space-3)' }}>
          {search ? 'No matching skills.' : 'No skills installed.'}
        </p>
      )}

      {/* Stats footer */}
      {hasLoaded && skills.length > 0 && (
        <div
          style={{
            marginTop: 'var(--space-2)',
            paddingTop: 'var(--space-2)',
            borderTop: '1px solid var(--border-subtle)',
            display: 'flex',
            gap: 'var(--space-3)',
            fontSize: 'var(--text-xs)',
            color: 'var(--text-muted)',
          }}
        >
          <span style={{ color: 'var(--success)' }}>✅ {readyCount} ready</span>
          {issueCount > 0 && (
            <span style={{ color: 'var(--warning)' }}>⚠️ {issueCount} need attention</span>
          )}
        </div>
      )}
    </DashboardSection>
  );
};

export default SkillsFolder;
