/**
 * Corgi Dashboard — CloudflareTileCard
 * Individual Cloudflare project tile (~200px wide).
 */
import React from 'react';
import { motion } from 'framer-motion';
import { ExternalLink, Globe } from 'lucide-react';

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type CloudflareProjectStatus = 'active' | 'building' | 'failed' | 'unknown';

export interface CloudflareProject {
  id: string;
  name: string;
  status: CloudflareProjectStatus;
  productionUrl?: string;
  /** Cloudflare dashboard URL for this project */
  dashboardUrl?: string;
  lastDeploy?: string;       // ISO 8601 or relative string
  lastDeployRelative?: string; // e.g. "2h ago"
  customDomains?: string[];
}

export interface CloudflareTileCardProps {
  project: CloudflareProject;
  onClick?: (project: CloudflareProject) => void;
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

const STATUS_DOT: Record<CloudflareProjectStatus, string> = {
  active: 'var(--success)',
  building: 'var(--warning)',
  failed: 'var(--error)',
  unknown: 'var(--text-muted)',
};

const STATUS_LABEL: Record<CloudflareProjectStatus, string> = {
  active: 'Active',
  building: 'Building',
  failed: 'Failed',
  unknown: '—',
};

function truncateUrl(url: string, max = 28): string {
  const clean = url.replace(/^https?:\/\//, '');
  return clean.length > max ? clean.slice(0, max - 1) + '…' : clean;
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const CloudflareTileCard: React.FC<CloudflareTileCardProps> = ({ project, onClick }) => {
  const dotColor = STATUS_DOT[project.status] ?? STATUS_DOT.unknown;
  const isBuilding = project.status === 'building';

  const handleClick = () => {
    const url = project.dashboardUrl ?? project.productionUrl;
    if (url) window.open(url, '_blank', 'noopener,noreferrer');
    onClick?.(project);
  };

  return (
    <motion.div
      onClick={handleClick}
      whileHover={{ scale: 1.02, y: -1 }}
      whileTap={{ scale: 0.98 }}
      transition={{ duration: 0.15, ease: [0.16, 1, 0.3, 1] }}
      style={{
        width: 200,
        flexShrink: 0,
        background: 'var(--bg-tertiary)',
        border: '1px solid var(--border-subtle)',
        borderRadius: 'var(--radius-lg)',
        padding: 'var(--space-3)',
        cursor: 'pointer',
        position: 'relative',
        display: 'flex',
        flexDirection: 'column',
        gap: 'var(--space-2)',
        userSelect: 'none',
        boxShadow: 'var(--shadow-subtle)',
        transition: 'box-shadow var(--transition-fast)',
      }}
      onMouseEnter={(e) => {
        (e.currentTarget as HTMLElement).style.boxShadow = 'var(--shadow-medium)';
        (e.currentTarget as HTMLElement).style.borderColor = 'var(--border-default)';
      }}
      onMouseLeave={(e) => {
        (e.currentTarget as HTMLElement).style.boxShadow = 'var(--shadow-subtle)';
        (e.currentTarget as HTMLElement).style.borderColor = 'var(--border-subtle)';
      }}
    >
      {/* Status dot — top-right corner */}
      <div
        style={{
          position: 'absolute',
          top: 10,
          right: 10,
          display: 'flex',
          alignItems: 'center',
          gap: 4,
        }}
      >
        {isBuilding ? (
          <motion.div
            style={{
              width: 7,
              height: 7,
              borderRadius: 'var(--radius-full)',
              background: dotColor,
            }}
            animate={{ opacity: [1, 0.3, 1] }}
            transition={{ duration: 1, repeat: Infinity, ease: 'easeInOut' }}
          />
        ) : (
          <div
            style={{
              width: 7,
              height: 7,
              borderRadius: 'var(--radius-full)',
              background: dotColor,
            }}
          />
        )}
      </div>

      {/* Project name */}
      <div
        style={{
          fontSize: 'var(--text-sm)',
          fontWeight: 'var(--font-semibold)',
          color: 'var(--text-primary)',
          paddingRight: 20,
          lineHeight: 'var(--leading-snug)',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          whiteSpace: 'nowrap',
        }}
        title={project.name}
      >
        {project.name}
      </div>

      {/* Status label */}
      <div
        style={{
          fontSize: 'var(--text-xs)',
          color: dotColor,
          fontWeight: 'var(--font-medium)',
        }}
      >
        {STATUS_LABEL[project.status]}
      </div>

      {/* Production URL */}
      {project.productionUrl && (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 4,
            fontSize: 'var(--text-xs)',
            fontFamily: 'var(--font-mono)',
            color: 'var(--text-muted)',
            overflow: 'hidden',
          }}
        >
          <Globe size={10} style={{ flexShrink: 0 }} />
          <span
            style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
            title={project.productionUrl}
          >
            {truncateUrl(project.productionUrl)}
          </span>
          <ExternalLink size={9} style={{ flexShrink: 0, opacity: 0.5 }} />
        </div>
      )}

      {/* Last deploy */}
      {project.lastDeployRelative && (
        <div
          style={{
            fontSize: 'var(--text-xs)',
            color: 'var(--text-muted)',
          }}
        >
          Deployed {project.lastDeployRelative}
        </div>
      )}

      {/* Custom domains */}
      {project.customDomains && project.customDomains.length > 0 && (
        <div
          style={{
            borderTop: '1px solid var(--border-subtle)',
            paddingTop: 'var(--space-1_5)',
            marginTop: 'var(--space-0_5)',
          }}
        >
          {project.customDomains.slice(0, 2).map((d) => (
            <div
              key={d}
              style={{
                fontSize: 'var(--text-xs)',
                fontFamily: 'var(--font-mono)',
                color: 'var(--info)',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
              title={d}
            >
              {d}
            </div>
          ))}
          {project.customDomains.length > 2 && (
            <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-muted)' }}>
              +{project.customDomains.length - 2} more
            </div>
          )}
        </div>
      )}
    </motion.div>
  );
};

/* ------------------------------------------------------------------ */
/*  Add tile (placeholder)                                             */
/* ------------------------------------------------------------------ */

export const CloudflareAddTile: React.FC<{ onClick?: () => void }> = ({ onClick }) => (
  <motion.div
    onClick={onClick}
    whileHover={{ scale: 1.02, y: -1 }}
    whileTap={{ scale: 0.98 }}
    transition={{ duration: 0.15, ease: [0.16, 1, 0.3, 1] }}
    style={{
      width: 200,
      flexShrink: 0,
      background: 'var(--bg-tertiary)',
      border: '1px dashed var(--border-default)',
      borderRadius: 'var(--radius-lg)',
      padding: 'var(--space-3)',
      cursor: 'pointer',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      gap: 'var(--space-2)',
      color: 'var(--text-muted)',
      minHeight: 110,
      userSelect: 'none',
    }}
  >
    <div
      style={{
        width: 28,
        height: 28,
        borderRadius: 'var(--radius-full)',
        border: '1.5px dashed var(--border-default)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        fontSize: 18,
      }}
    >
      +
    </div>
    <span style={{ fontSize: 'var(--text-xs)' }}>Add project</span>
  </motion.div>
);

export default CloudflareTileCard;
